using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public record ClassifyRequest(string Subject, string Description, int Priority);

public record ClassifyResponse(
    string PredictedCategory,
    Dictionary<string, float> ConfidenceScores);

public record EvaluationMetrics(
    double MicroAccuracy,
    double MacroAccuracy,
    double LogLoss,
    double LogLossReduction,
    Dictionary<string, CategoryMetrics> PerCategoryMetrics);

public record CategoryMetrics(
    double Precision,
    double Recall,
    double F1Score);

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _metrics;
    private readonly string[] _categoryNames;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(split.TrainSet);

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract ordered category names from the label key mapping
        var labelColumn = split.TrainSet.Schema["Label"];
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        split.TrainSet.Schema["Label"].GetKeyValues(ref keyValues);
        _categoryNames = keyValues.DenseValues()
            .Select(v => v.ToString()).ToArray();

        var predictions = _model.Transform(split.TestSet);
        var mlMetrics = _mlContext.MulticlassClassification
            .Evaluate(predictions, labelColumnName: "Label");

        var perCategory = new Dictionary<string, CategoryMetrics>();
        for (int i = 0; i < mlMetrics.PerClassLogLoss.Count && i < _categoryNames.Length; i++)
        {
            perCategory[_categoryNames[i]] = new CategoryMetrics(
                Precision: mlMetrics.ConfusionMatrix.PerClassPrecision[i],
                Recall: mlMetrics.ConfusionMatrix.PerClassRecall[i],
                F1Score: 2 * mlMetrics.ConfusionMatrix.PerClassPrecision[i]
                           * mlMetrics.ConfusionMatrix.PerClassRecall[i]
                         / (mlMetrics.ConfusionMatrix.PerClassPrecision[i]
                           + mlMetrics.ConfusionMatrix.PerClassRecall[i] + 1e-15));
        }

        _metrics = new EvaluationMetrics(
            MicroAccuracy: mlMetrics.MicroAccuracy,
            MacroAccuracy: mlMetrics.MacroAccuracy,
            LogLoss: mlMetrics.LogLoss,
            LogLossReduction: mlMetrics.LogLossReduction,
            PerCategoryMetrics: perCategory);
    }

    public ClassifyResponse Classify(ClassifyRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidenceScores = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _categoryNames.Length; i++)
        {
            confidenceScores[_categoryNames[i]] = prediction.Score[i];
        }

        return new ClassifyResponse(prediction.PredictedLabel, confidenceScores);
    }

    public EvaluationMetrics GetMetrics() => _metrics;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest("Subject is required.");

        if (string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(classifier.Classify(request));
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        return Ok(classifier.GetMetrics());
    }
}

